nodes.notes:
International weather — current conditions or multi-day forecast for Australia, Canada, France, and the USA.

Actions:
  current — right now conditions. Use for "what's the weather", "is it raining", "temperature in X".
  forecast — multi-day outlook. Use for "forecast", "this week", "will it rain Thursday", "weekend weather".

Region mapping (match the city to its country):
  aus — Australian cities: Sydney, Melbourne, Brisbane, Perth, Adelaide, Canberra, Gold Coast, Darwin
  can — Canadian cities: Toronto, Vancouver, Montreal, Ottawa, Calgary, Edmonton, Winnipeg, Halifax
  fra — French cities: Paris, Lyon, Marseille, Toulouse, Nice, Bordeaux, Strasbourg
  us — American cities: New York, Chicago, Los Angeles, Houston, Miami, Seattle, Boston, Denver, Dallas

Rules:
- region and location are always required.
- If unsure about region, pick the most common country for that city name.
- days is 1-7 for forecast. Default varies by region (3 US, 7 AUS, 5 FRA/CAN).
- target_day is for asking about a specific day, e.g. "What's the weather on Thursday?"

---schema
{
  "action": {
    "type": "string",
    "description": "One of: current, forecast",
    "required": true
  },
  "region": {
    "type": "string",
    "required": true,
    "description": "Region code for weather data source. One of: aus, can, fra, us"
  },
  "location": {
    "type": "string",
    "required": true,
    "description": "City name, e.g. Vancouver, Sydney, Paris, Chicago"
  },
  "days": {
    "type": "integer",
    "description": "Forecast days, 1-7. Default varies by region. For: forecast"
  },
  "target_day": {
    "type": "string",
    "description": "Specific weekday, e.g. Thursday, Saturday. For: forecast"
  }
}

parameters.jsCode:
const body = $input.item.json.body || $input.item.json;

const region = (body.region || '').toLowerCase();
const action = (body.action || 'forecast').toLowerCase();
const rawLocation = (body.location || '').toString().trim();
const days = parseInt(body.days) || null;
const target_day = body.target_day ? body.target_day.toString().trim() : null;

if (!region || !['aus', 'can', 'fra', 'us'].includes(region)) {
  return { error: true, message: "Region is required. Use 'aus', 'can', 'fra', or 'us'." };
}
if (!rawLocation) {
  return { error: true, message: 'Location is required.' };
}

return { region, action, location: rawLocation, days, target_day, error: false };

const params = $('Parse Input').item.json;
const rawLocation = params.location;
const location = /^\d+$/.test(rawLocation)
  ? rawLocation
  : rawLocation.toLowerCase().replace(/\b[a-z]/g, c => c.toUpperCase());
const days = Math.min(Math.max(params.days || 7, 1), 7);
return {
  action: params.action,
  location,
  days,
  target_day: params.target_day,
  searchUrl: `https://api.weather.bom.gov.au/v1/locations?search=${encodeURIComponent(location)}`
};

const raw = $input.item.json;
const params = $('AUS: Prepare').item.json;
if (!raw.data || raw.data.length === 0) {
  return { error: true, message: `Sorry, I couldn't find weather data for "${params.location}".` };
}
const loc = raw.data[0];
const fullGeohash = loc.geohash;
const hourlyGeohash = typeof fullGeohash === 'string' && fullGeohash.length > 6 ? fullGeohash.slice(0, 6) : fullGeohash;
return {
  error: false,
  locationName: `${loc.name}, ${loc.state}`,
  geohash: fullGeohash,
  forecastUrl: `https://api.weather.bom.gov.au/v1/locations/${fullGeohash}/forecasts/daily`,
  hourlyUrl: `https://api.weather.bom.gov.au/v1/locations/${hourlyGeohash}/forecasts/hourly`,
  days: params.days,
  target_day: params.target_day
};

const data = $input.item.json.data || [];
const params = $('AUS: Parse Location').item.json;
let periods = data;
if (params.target_day) {
  const target = params.target_day.toLowerCase().replace(/^\w/, c => c.toUpperCase());
  periods = periods.filter(p => new Date(p.date).toLocaleDateString('en-AU', { weekday: 'long' }) === target);
  if (periods.length === 0) {
    return { error: true, message: `Sorry, I couldn't find a forecast for ${target} in ${params.locationName}.` };
  }
} else {
  periods = periods.slice(0, params.days);
}
function formatDay(d) {
  const date = new Date(d);
  const today = new Date();
  const tomorrow = new Date(today); tomorrow.setDate(today.getDate() + 1);
  if (date.toDateString() === today.toDateString()) return 'Today';
  if (date.toDateString() === tomorrow.toDateString()) return 'Tomorrow';
  return date.toLocaleDateString('en-AU', { weekday: 'long' });
}
const parts = periods.map(p => {
  const day = formatDay(p.date);
  const summary = (p.short_text || p.extended_text || 'No details').replace(/\.$/, '');
  const min = p.temp_min ?? 'unknown';
  const max = p.temp_max ?? 'unknown';
  const rain = p.rain?.chance != null ? `${p.rain.chance} percent chance of rain` : 'unknown rain chance';
  return `${day} is ${summary}, ${min} to ${max} degrees, with ${rain}`;
});
return {
  error: false,
  message: `Forecast for ${params.locationName}: ${parts.join('. ')}.`,
  location: params.locationName,
  forecasts: periods.map(p => ({ date: p.date, day: formatDay(p.date), temp_min: p.temp_min, temp_max: p.temp_max, summary: p.short_text, rain_chance: p.rain?.chance ?? null }))
};

const data = $input.item.json.data || [];
const params = $('AUS: Parse Location').item.json;
const now = new Date();
if (!data.length) { return { error: true, message: 'No current weather data available.' }; }
const current = data.find(p => new Date(p.time) >= now) || data[data.length - 1];
if (!current) { return { error: true, message: 'No current weather data available.' }; }
const temp = current.temp;
const feels = current.temp_feels_like;
const rain = current.rain?.chance ?? null;
const humidity = current.relative_humidity ?? null;
const uv = current.uv ?? null;
let parts = [`It is currently ${temp} degrees in ${params.locationName}`];
if (feels != null) parts.push(`feels like ${feels}`);
if (rain != null) parts.push(`with a ${rain} percent chance of rain`);
if (humidity != null) parts.push(`humidity ${humidity} percent`);
if (uv != null) parts.push(`UV index ${uv}`);
return { error: false, message: parts.join(', ') + '.', location: params.locationName, current: { temp, feels_like: feels, rain_chance: rain, humidity, uv } };

const params = $('Parse Input').item.json;
const rawLocation = params.location;
const location = rawLocation.replace(/\b[a-z]/g, c => c.toUpperCase());
const days = Math.min(Math.max(params.days || 5, 1), 6);
const accentMap = {
  'montreal': 'Montr\u00e9al', 'quebec': 'Qu\u00e9bec', 'quebec city': 'Qu\u00e9bec',
  'trois-rivieres': 'Trois-Rivi\u00e8res', 'levis': 'L\u00e9vis', 'gaspe': 'Gasp\u00e9'
};
const searchTerm = accentMap[rawLocation.toLowerCase()] || rawLocation;
return {
  action: params.action, location, days, target_day: params.target_day,
  searchUrl: `https://api.weather.gc.ca/collections/citypageweather-realtime/items?lang=en&f=json&q=${encodeURIComponent(searchTerm)}&limit=10`
};

const raw = $input.item.json;
const params = $('CAN: Prepare').item.json;
const features = raw.features || [];
if (features.length === 0) {
  return { error: true, message: `Sorry, I couldn't find weather data for "${params.location}". Try a major Canadian city name.` };
}
function norm(s) { return (s || '').normalize('NFD').replace(/[\u0300-\u036f]/g, '').toLowerCase(); }
const search = norm(params.location);
let best = features[0];
for (const f of features) {
  const name = norm(f.properties?.name?.en || '');
  if (name === search) { best = f; break; }
  if (name.startsWith(search) && norm(best.properties?.name?.en || '') !== search) { best = f; }
}
const props = best.properties;
const rawForecasts = props.forecastGroup?.forecasts || [];
const seen = new Set();
const forecasts = rawForecasts.filter(f => {
  const key = f.period?.textForecastName?.en || '';
  if (seen.has(key)) return false;
  seen.add(key); return true;
});
return {
  error: false, locationName: props.name?.en || params.location,
  region: props.region?.en || '', currentConditions: props.currentConditions || null,
  forecasts, warnings: props.warnings || [], days: params.days, target_day: params.target_day
};

const data = $input.item.json;
const params = $('CAN: Prepare').item.json;
const forecasts = data.forecasts || [];
if (forecasts.length === 0) { return { error: true, message: `No forecast data available for ${data.locationName}.` }; }
let periods = forecasts;
if (params.target_day) {
  const target = params.target_day.toLowerCase();
  periods = periods.filter(f => { const name = (f.period?.textForecastName?.en || '').toLowerCase(); return name.includes(target); });
  if (periods.length === 0) { return { error: true, message: `Sorry, I couldn't find a forecast for ${params.target_day} in ${data.locationName}.` }; }
} else {
  const dayPeriods = [];
  for (let i = 0; i < periods.length; i++) {
    const name = (periods[i].period?.textForecastName?.en || '').toLowerCase();
    if (i === 0 && name === 'tonight') { dayPeriods.push(periods[i]); }
    else if (!name.includes('night')) { dayPeriods.push(periods[i]); }
  }
  periods = dayPeriods.slice(0, params.days);
}
const parts = periods.map(f => {
  const name = f.period?.textForecastName?.en || 'Unknown';
  const temps = f.temperatures?.temperature || [];
  const high = temps.find(t => t.class?.en === 'high');
  const low = temps.find(t => t.class?.en === 'low');
  const summary = f.abbreviatedForecast?.textSummary?.en || f.cloudPrecip?.en || 'No details';
  let tempStr = '';
  if (high) tempStr = `high ${high.value?.en}`;
  if (low) tempStr = tempStr ? `${tempStr}, low ${low.value?.en}` : `low ${low.value?.en}`;
  return `${name}: ${summary}, ${tempStr}`;
});
let warningNote = '';
if (data.warnings && data.warnings.length > 0) { warningNote = ` Warning in effect for ${data.locationName}.`; }
return {
  error: false, message: `Forecast for ${data.locationName}: ${parts.join('. ')}.${warningNote}`,
  location: data.locationName,
  forecasts: periods.map(f => {
    const temps = f.temperatures?.temperature || [];
    const high = temps.find(t => t.class?.en === 'high');
    const low = temps.find(t => t.class?.en === 'low');
    return { period: f.period?.textForecastName?.en, high: high?.value?.en ?? null, low: low?.value?.en ?? null, summary: f.abbreviatedForecast?.textSummary?.en, text: f.textSummary?.en };
  })
};

const data = $input.item.json;
const cc = data.currentConditions;
if (!cc || cc.temperature?.value?.en == null) { return { error: true, message: `No current weather data available for ${data.locationName}.` }; }
const temp = cc.temperature.value.en;
const condition = cc.condition?.en || 'conditions not reported';
const windSpeed = cc.wind?.speed?.value?.en;
const windDir = cc.wind?.direction?.value?.en;
const windChill = cc.windChill?.value?.en;
const humidex = cc.humidex?.value?.en;
const humidity = cc.relativeHumidity?.value?.en;
const gust = cc.wind?.gust?.value?.en;
let parts = [`It is currently ${temp} degrees in ${data.locationName}, ${condition.toLowerCase()}`];
if (windChill != null) parts.push(`feels like ${windChill}`);
else if (humidex != null) parts.push(`feels like ${humidex}`);
if (windSpeed != null && windDir) { let windPart = `wind ${windDir} at ${windSpeed} km/h`; if (gust != null && gust > 0) windPart += ` gusting to ${gust}`; parts.push(windPart); }
if (humidity != null) parts.push(`humidity ${humidity} percent`);
if (data.warnings && data.warnings.length > 0) { parts.push('weather warning in effect'); }
return { error: false, message: parts.join(', ') + '.', location: data.locationName, current: { temp, condition, wind_chill: windChill ?? null, humidex: humidex ?? null, wind_speed: windSpeed ?? null, wind_direction: windDir ?? null, gust: gust ?? null, humidity: humidity ?? null } };

const params = $('Parse Input').item.json;
const rawLocation = params.location;
const location = rawLocation.replace(/\b[a-z]/g, c => c.toUpperCase());
const days = Math.min(Math.max(params.days || 5, 1), 7);
const accentMap = {
  'orleans': 'Orl\u00e9ans', 'beziers': 'B\u00e9ziers', 'nimes': 'N\u00eemes',
  'clermont ferrand': 'Clermont-Ferrand', 'saint etienne': 'Saint-\u00c9tienne',
  'le mans': 'Le Mans', 'aix en provence': 'Aix-en-Provence'
};
const searchTerm = accentMap[rawLocation.toLowerCase()] || rawLocation;
return {
  action: params.action, location, days, target_day: params.target_day,
  searchUrl: `https://geocoding-api.open-meteo.com/v1/search?name=${encodeURIComponent(searchTerm)}&count=10&language=fr`
};

const raw = $input.item.json;
const params = $('FRA: Prepare').item.json;
const results = (raw.results || []);
const frResults = results.filter(r => r.country_code === 'FR');
const best = frResults.length > 0 ? frResults[0] : null;
if (!best) { return { error: true, message: `Ville ${params.location} introuvable en France. Essayez un nom de ville fran\u00e7aise.` }; }
const forecastDays = Math.min(params.days + 1, 7);
return {
  error: false, location: best.name || params.location, region: best.admin1 || '',
  latitude: best.latitude, longitude: best.longitude,
  action: params.action, days: params.days, target_day: params.target_day,
  weatherUrl: `https://api.open-meteo.com/v1/forecast?latitude=${best.latitude}&longitude=${best.longitude}&current=temperature_2m,relative_humidity_2m,apparent_temperature,weather_code,wind_speed_10m,wind_direction_10m,precipitation&daily=temperature_2m_max,temperature_2m_min,precipitation_sum,precipitation_probability_max,weather_code,wind_speed_10m_max,wind_direction_10m_dominant&timezone=Europe/Paris&forecast_days=${forecastDays}`
};

const weather = $input.item.json;
const params = $('FRA: Parse Geocode').item.json;
const daily = weather.daily;
if (!daily || !daily.time) { return { error: true, message: `Pas de donn\u00e9es de pr\u00e9vision pour ${params.location}.` }; }
const weatherCodes = {
  0: 'Ciel d\u00e9gag\u00e9', 1: 'Principalement d\u00e9gag\u00e9', 2: 'Partiellement nuageux', 3: 'Couvert',
  45: 'Brouillard', 48: 'Brouillard givrant',
  51: 'Bruine l\u00e9g\u00e8re', 53: 'Bruine mod\u00e9r\u00e9e', 55: 'Bruine dense',
  56: 'Bruine vergla\u00e7ante', 57: 'Bruine vergla\u00e7ante dense',
  61: 'Pluie l\u00e9g\u00e8re', 63: 'Pluie mod\u00e9r\u00e9e', 65: 'Pluie forte',
  66: 'Pluie vergla\u00e7ante', 67: 'Pluie vergla\u00e7ante forte',
  71: 'Neige l\u00e9g\u00e8re', 73: 'Neige mod\u00e9r\u00e9e', 75: 'Neige forte', 77: 'Grains de neige',
  80: 'Averses l\u00e9g\u00e8res', 81: 'Averses mod\u00e9r\u00e9es', 82: 'Averses violentes',
  85: 'Averses de neige l\u00e9g\u00e8res', 86: 'Averses de neige fortes',
  95: 'Orage', 96: 'Orage avec gr\u00eale', 99: 'Orage avec forte gr\u00eale'
};
const dayNames = ['Dimanche', 'Lundi', 'Mardi', 'Mercredi', 'Jeudi', 'Vendredi', 'Samedi'];
let forecasts = [];
for (let i = 0; i < daily.time.length; i++) {
  const date = new Date(daily.time[i] + 'T12:00:00');
  forecasts.push({
    date: daily.time[i], day: dayNames[date.getDay()],
    temp_min: daily.temperature_2m_min[i], temp_max: daily.temperature_2m_max[i],
    precipitations: daily.precipitation_sum[i],
    conditions: weatherCodes[daily.weather_code[i]] || ('Code ' + daily.weather_code[i]),
    wind_max: daily.wind_speed_10m_max[i]
  });
}
if (params.target_day) {
  const target = params.target_day.toLowerCase();
  forecasts = forecasts.filter(f => f.day.toLowerCase().includes(target));
  if (forecasts.length === 0) { return { error: true, message: `Pas de pr\u00e9vision pour ${params.target_day} \u00e0 ${params.location}.` }; }
} else { forecasts = forecasts.slice(0, params.days); }
const parts = forecasts.map(f => `${f.day} ${f.date}: ${f.conditions}, ${f.temp_min}\u00b0C \u00e0 ${f.temp_max}\u00b0C`);
return { error: false, message: `Pr\u00e9visions pour ${params.location}: ${parts.join('. ')}.`, location: params.location, region: params.region, forecasts };

const weather = $input.item.json;
const params = $('FRA: Parse Geocode').item.json;
const current = weather.current;
if (!current || current.temperature_2m == null) { return { error: true, message: `Pas de donn\u00e9es m\u00e9t\u00e9o actuelles pour ${params.location}.` }; }
const weatherCodes = {
  0: 'ciel d\u00e9gag\u00e9', 1: 'principalement d\u00e9gag\u00e9', 2: 'partiellement nuageux', 3: 'couvert',
  45: 'brouillard', 48: 'brouillard givrant',
  51: 'bruine l\u00e9g\u00e8re', 53: 'bruine mod\u00e9r\u00e9e', 55: 'bruine dense',
  61: 'pluie l\u00e9g\u00e8re', 63: 'pluie mod\u00e9r\u00e9e', 65: 'pluie forte',
  71: 'neige l\u00e9g\u00e8re', 73: 'neige mod\u00e9r\u00e9e', 75: 'neige forte',
  80: 'averses l\u00e9g\u00e8res', 81: 'averses mod\u00e9r\u00e9es', 82: 'averses violentes',
  95: 'orage', 96: 'orage avec gr\u00eale', 99: 'orage avec forte gr\u00eale'
};
const temp = current.temperature_2m;
const apparent = current.apparent_temperature;
const condition = weatherCodes[current.weather_code] || ('code ' + current.weather_code);
const windSpeed = current.wind_speed_10m;
const windDir = current.wind_direction_10m;
const humidity = current.relative_humidity_2m;
function windCardinal(deg) { const dirs = ['N', 'NE', 'E', 'SE', 'S', 'SO', 'O', 'NO']; return dirs[Math.round(deg / 45) % 8]; }
const parts = [`Il fait actuellement ${temp} degr\u00e9s \u00e0 ${params.location}, ${condition}`];
if (apparent != null && Math.abs(apparent - temp) >= 2) { parts.push(`ressenti ${apparent}`); }
if (windSpeed != null && windDir != null) { parts.push(`vent ${windCardinal(windDir)} \u00e0 ${windSpeed} km/h`); }
if (humidity != null) { parts.push(`humidit\u00e9 ${humidity}%`); }
return { error: false, message: parts.join(', ') + '.', location: params.location, region: params.region, current: { temp, apparent_temp: apparent, condition, wind_speed: windSpeed, wind_direction: windDir != null ? windCardinal(windDir) : null, humidity, precipitation: current.precipitation } };

const params = $('Parse Input').item.json;
const rawLocation = params.location;
const normalizedLocation = rawLocation.replace(/,/g, ' ').replace(/\s+/g, ' ').trim();
const parts = normalizedLocation.split(' ');
let city = '', state = '';
if (parts.length >= 2) {
  const lastWord = parts[parts.length - 1];
  if (lastWord.length === 2 || lastWord.length > 4) { state = lastWord; city = parts.slice(0, -1).join(' '); }
  else { city = parts.join(' '); }
} else { city = normalizedLocation; }
let geocodeUrl;
if (state) { geocodeUrl = `https://nominatim.openstreetmap.org/search?city=${encodeURIComponent(city)}&state=${encodeURIComponent(state)}&country=USA&format=json&limit=1`; }
else { geocodeUrl = `https://nominatim.openstreetmap.org/search?q=${encodeURIComponent(normalizedLocation)}&countrycodes=us&format=json&limit=1`; }
const days = Math.min(Math.max(params.days || 3, 1), 7);
return { action: params.action, location: normalizedLocation, days, target_day: params.target_day, geocodeUrl };

const geocodeData = $input.item.json;
const params = $('US: Prepare').item.json;
let result;
if (Array.isArray(geocodeData)) {
  if (geocodeData.length === 0) { return { error: true, message: `Sorry, I couldn't find "${params.location}". Try including the full state name like "Chicago Illinois".` }; }
  result = geocodeData[0];
} else if (geocodeData && geocodeData.lat && geocodeData.lon) { result = geocodeData; }
else { return { error: true, message: `Sorry, I couldn't find "${params.location}". Try including the full state name like "Chicago Illinois".` }; }
const lat = parseFloat(result.lat);
const lon = parseFloat(result.lon);
if (isNaN(lat) || isNaN(lon)) { return { error: true, message: `Sorry, invalid coordinates for "${params.location}".` }; }
const displayName = result.display_name || params.location;
const dpParts = displayName.split(',').map(p => p.trim());
let city = dpParts[0] || 'Unknown';
let state = '';
for (const part of dpParts) { if (part.length === 2 && /^[A-Z]{2}$/.test(part)) { state = part; break; } }
if (!state && dpParts.length >= 2) { state = dpParts[dpParts.length - 2] || ''; }
const roundedLat = Math.round(lat * 10000) / 10000;
const roundedLon = Math.round(lon * 10000) / 10000;
return {
  error: false, latitude: roundedLat, longitude: roundedLon, city, state, displayName,
  pointsUrl: `https://api.weather.gov/points/${roundedLat},${roundedLon}`,
  action: params.action, days: params.days, target_day: params.target_day
};

const pointsData = $input.item.json;
const geocodeData = $('US: Parse Geocode').item.json;
if (!pointsData.properties) { return { error: true, message: `Sorry, weather data is not available for this location.` }; }
const properties = pointsData.properties || {};
const forecastUrl = properties.forecast || '';
const forecastHourlyUrl = properties.forecastHourly || '';
const observationStations = properties.observationStations || '';
if (!forecastUrl) { return { error: true, message: `Sorry, no forecast available for ${geocodeData.city}.` }; }
return {
  error: false, city: geocodeData.city, state: geocodeData.state,
  latitude: geocodeData.latitude, longitude: geocodeData.longitude,
  forecastUrl, forecastHourlyUrl, observationStations,
  action: geocodeData.action, days: geocodeData.days, target_day: geocodeData.target_day
};

const forecastData = $input.item.json;
const pointsData = $('US: Extract Points Data').item.json;
if (!forecastData.properties || !forecastData.properties.periods) { return { error: true, message: `Sorry, no forecast data available for ${pointsData.city}.` }; }
const periods = forecastData.properties.periods || [];
if (periods.length === 0) { return { error: true, message: `Sorry, no forecast periods available for ${pointsData.city}.` }; }
let filteredPeriods = periods;
if (pointsData.target_day) {
  const target = pointsData.target_day.toLowerCase();
  filteredPeriods = periods.filter(p => { const name = (p.name || '').toLowerCase(); return name.includes(target); });
  if (filteredPeriods.length === 0) { return { error: true, message: `Sorry, I couldn't find a forecast for ${pointsData.target_day} in ${pointsData.city}.` }; }
} else {
  const dayPeriods = [];
  for (let i = 0; i < periods.length; i++) {
    const p = periods[i]; const name = (p.name || '').toLowerCase();
    if (i === 0 && name.includes('tonight')) { dayPeriods.push(p); }
    else if (p.isDaytime || i === 0) { dayPeriods.push(p); }
    if (dayPeriods.length >= pointsData.days) break;
  }
  filteredPeriods = dayPeriods;
}
const voiceParts = filteredPeriods.map(p => {
  const name = p.name || 'Unknown';
  const temp = p.temperature || 'unknown';
  const forecast = p.shortForecast || 'no details';
  const wind = p.windSpeed || '';
  let part = `${name}: ${forecast}, ${temp} degrees`;
  if (wind && !wind.toLowerCase().includes('calm') && wind !== '0 mph') { part += `, wind ${wind}`; }
  return part;
});
const locationStr = pointsData.state ? `${pointsData.city}, ${pointsData.state}` : pointsData.city;
const message = `${locationStr}. ${voiceParts.join('. ')}.`;
return {
  error: false, message, location: pointsData.city, state: pointsData.state,
  forecasts: filteredPeriods.map(p => ({ name: p.name, temperature: p.temperature, temperatureUnit: p.temperatureUnit || 'F', shortForecast: p.shortForecast, detailedForecast: p.detailedForecast, windSpeed: p.windSpeed, windDirection: p.windDirection, isDaytime: p.isDaytime }))
};

const stationsData = $input.item.json;
const pointsData = $('US: Extract Points Data').item.json;
if (!stationsData.features || stationsData.features.length === 0) { return { error: true, message: `Sorry, no observation stations found for ${pointsData.city}.` }; }
const stationId = stationsData.features[0].properties.stationIdentifier;
return { stationId, observationUrl: `https://api.weather.gov/stations/${stationId}/observations/latest`, city: pointsData.city, state: pointsData.state };

const obsData = $input.item.json;
const stationData = $('US: Extract Station').item.json;
if (!obsData.properties) { return { error: true, message: `Sorry, no current weather data available for ${stationData.city}.` }; }
const props = obsData.properties;
const tempC = props.temperature?.value;
const tempF = tempC != null ? Math.round((tempC * 9/5) + 32) : null;
const condition = props.textDescription || 'conditions not reported';
const windSpeedKmh = props.windSpeed?.value;
const windSpeedMph = windSpeedKmh != null ? Math.round(windSpeedKmh * 0.621371) : null;
const windDir = props.windDirection?.value;
const humidity = props.relativeHumidity?.value;
if (tempF == null) { return { error: true, message: `Sorry, current temperature not available for ${stationData.city}.` }; }
const locationStr = stationData.state ? `${stationData.city}, ${stationData.state}` : stationData.city;
let parts = [`Currently ${tempF} degrees in ${locationStr}, ${condition.toLowerCase()}`];
if (windSpeedMph != null && windSpeedMph > 0 && windDir != null) {
  const windDirDeg = Math.round(windDir);
  const directions = ['north', 'northeast', 'east', 'southeast', 'south', 'southwest', 'west', 'northwest'];
  const dirIndex = Math.round(windDirDeg / 45) % 8;
  parts.push(`wind ${directions[dirIndex]} at ${windSpeedMph} mph`);
}
if (humidity != null) { parts.push(`humidity ${Math.round(humidity)} percent`); }
return { error: false, message: parts.join(', ') + '.', location: stationData.city, state: stationData.state, current: { temp: tempF, tempUnit: 'F', condition, windSpeed: windSpeedMph, windDirection: windDir, humidity: humidity ? Math.round(humidity) : null } };

const error = $input.item.json;
let message = 'Sorry, there was an error connecting to the weather service.';
if (error.message) {
  if (error.message.includes('ECONNREFUSED') || error.message.includes('ETIMEDOUT')) {
    message = 'Sorry, the weather service is currently unreachable. Please try again later.';
  } else if (error.message.includes('500') || error.message.includes('503')) {
    message = 'Sorry, the weather service is experiencing issues. Please try again later.';
  }
}
return { error: true, message };
